const baseUrl = "https://www.bam.co.th/search?pageSize=24&filter_name=ทั้งหมด";
const source = "BAM";
const selector = 'div[src*="asset-small"]';
const subSelector = 'div.d-flex.flex-column';
const realBaseUrl = "https://www.bam.co.th/propertydetail/";

const page_start = 1;
const page_stop = 5;

// --------------------
// Filters
// --------------------
const regions = [
  { name: "กรุงเทพมหานคร"},
  { name: "นนทบุรี"}
];

const propertyTypes = [
  { name: "ทาวน์เฮ้าส์"},
  { name: "บ้านเดี่ยว"},
  { name: "ที่ดินเปล่า"},
  { name: "ห้องชุดพักอาศัย"}
];

const items = [];

for (const region of regions) {
  for (const property of propertyTypes) {
    for (let page = page_start; page <= page_stop; page++) {


      const suffixUrl =
      `&province=${region.name}` +
      `&assetType=${property.name}` +
      `&pageNumber=${page}`

      items.push({
        url: `${baseUrl}${suffixUrl}`,
        selector,
        source,
        subSelector,
        realBaseUrl
      });

    }

  }
}

return items;

// เปลี่ยนจาก items[0] เป็นการรวบรวมข้อมูลจากทุก Item
const allExtracted = items.flatMap(item => item.json.solution?.extracted_data ?? []);

const urls = [...new Set(
  allExtracted
    .map(x => {
      const html = x.html || "";
      const m = html.match(/-(\d+)-\d+\.jpg/);
      return m ? $('Generate Main Page URL List').first().json.realBaseUrl + m[1] : null;
    })
    .filter(Boolean)
)];

return urls.map(rawUrl => {
  let decodedUrl = rawUrl;
  try {
    const u = new URL(rawUrl);
    decodedUrl = u.origin + decodeURIComponent(u.pathname) + u.search;
  } catch (e) {
    decodedUrl = decodeURIComponent(rawUrl);
  }

  // ใช้ metadata จากหน้าแรก
  const firstItem = items[0].json; 
  return {
    json: {
      url: decodedUrl,
      source: $('Generate Main Page URL List').first().json.source,
      selector: $('Generate Main Page URL List').first().json.subSelector,
      method: $('Generate Main Page URL List').first().json.method
    }
  };
});

// 1. รวบรวมข้อมูลและจัดการ URL ก่อนทำ Filtering
const allData = items
  .map(item => {
    let rawUrl = item.json.solution?.url || "";
    let decodedUrl = rawUrl;

    if (rawUrl) {
      try {
        const urlWithoutFragment = rawUrl.split('#')[0];
        const u = new URL(urlWithoutFragment);
        decodedUrl = u.origin + decodeURIComponent(u.pathname) + u.search;
      } catch (e) {
        decodedUrl = decodeURIComponent(rawUrl.split('#')[0]);
      }
    }

    // --- ส่วนที่ Filter คำที่ต้องการ และจำกัดจำนวนไว้ที่ 3 ตัวแรก ---
    let rawExtracted = item.json.solution?.extracted_data;
    let filteredExtracted = [];

    if (Array.isArray(rawExtracted)) {
      filteredExtracted = rawExtracted
        .filter(ex => {
          const htmlText = ex.html || "";
          // กรองเอาเฉพาะที่มีคำที่ต้องการ
          return htmlText.includes("บริษัทขอสงวนสิทธิ์") || htmlText.includes("รายละเอียดทรัพย์");
        })
        .slice(0, 3); // <--- เพิ่มตรงนี้: เอาแค่ 3 ตัวแรกที่ผ่านการกรองแล้ว
    } else if (typeof rawExtracted === 'object' && rawExtracted !== null) {
      const htmlText = rawExtracted.html || "";
      if (htmlText.includes("บริษัทขอสงวนสิทธิ์") || htmlText.includes("รายละเอียดทรัพย์")) {
        filteredExtracted = [rawExtracted];
      }
    }

    return {
      url: decodedUrl,
      extracted_data: filteredExtracted
    };
  })
  .filter(item => {
    const data = item.extracted_data;
    // ถ้าไม่มี html ตัวไหนตรงเงื่อนไขเลย (เหลือ 0 ตัว) ให้ตัด Item นี้ทิ้งทั้งก้อน
    if (!data || (Array.isArray(data) && data.length === 0)) return false;
    if (!item.url || item.url.trim() === "") return false;
    return true;
  });

// 2. แบ่งกลุ่ม (Chunking) ละ 15 ตัว
const chunkSize = 15;
const results = [];

for (let i = 0; i < allData.length; i += chunkSize) {
  const chunk = allData.slice(i, i + chunkSize);
  results.push({
    json: {
      data_set: chunk,
      count: chunk.length,
      source: $('Generate Main Page URL List').first().json.source
    }
  });
}

return results;
